typedef float fp;

__kernel void extract_kernel(long d_Ne,
                             __global fp *d_I) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / (fp)255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global fp *d_I,
                             __global fp *d_sums,
                             __global fp *d_sums2) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        fp v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global fp *d_sums,
                            __global fp *d_sums2,
                            int d_blocks) {
    (void)d_Ne;
    (void)d_blocks;

    const int lid = get_local_id(0);
    const int lsize = get_local_size(0);
    const int group = get_group_id(0);

    if (lid == 0) {
        long start = (long)group * (long)lsize;
        long end = start + (long)lsize;
        if (end > d_no) end = d_no;

        fp sum = 0.0f;
        fp sum2 = 0.0f;

        for (long i = start; i < end; i++) {
            long idx = i * (long)d_mul;
            sum += d_sums[idx];
            sum2 += d_sums2[idx];
        }

        long out_idx = (long)group * (long)d_mul * (long)lsize;
        d_sums[out_idx] = sum;
        d_sums2[out_idx] = sum2;
    }
}

__kernel void srad_kernel(fp lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *d_iN,
                          __global int *d_iS,
                          __global int *d_jE,
                          __global int *d_jW,
                          __global fp *d_dN,
                          __global fp *d_dS,
                          __global fp *d_dW,
                          __global fp *d_dE,
                          fp q0sqr,
                          __global fp *d_c,
                          __global fp *d_I) {
    (void)lambda;
    (void)Nr;

    long k = (long)get_global_id(0);
    if (k < Ne) {
        int i = (int)(k / (long)Nc);
        int j = (int)(k - (long)i * (long)Nc);

        fp Jc = d_I[k];

        int iN = d_iN[i];
        int iS = d_iS[i];
        int jW = d_jW[j];
        int jE = d_jE[j];

        d_dN[k] = d_I[(long)iN * (long)Nc + (long)j] - Jc;
        d_dS[k] = d_I[(long)iS * (long)Nc + (long)j] - Jc;
        d_dW[k] = d_I[(long)i * (long)Nc + (long)jW] - Jc;
        d_dE[k] = d_I[(long)i * (long)Nc + (long)jE] - Jc;

        fp G2 = (d_dN[k] * d_dN[k] + d_dS[k] * d_dS[k] +
                 d_dW[k] * d_dW[k] + d_dE[k] * d_dE[k]) / (Jc * Jc);

        fp L = (d_dN[k] + d_dS[k] + d_dW[k] + d_dE[k]) / Jc;

        fp num = (fp)0.5f * G2 - (fp)(1.0f / 16.0f) * (L * L);
        fp den = (fp)1.0f + (fp)0.25f * L;
        fp qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * ((fp)1.0f + q0sqr));
        fp c = (fp)1.0f / ((fp)1.0f + den);

        if (c < (fp)0.0f) c = (fp)0.0f;
        else if (c > (fp)1.0f) c = (fp)1.0f;

        d_c[k] = c;
    }
}

__kernel void srad2_kernel(fp lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *d_iN,
                           __global int *d_iS,
                           __global int *d_jE,
                           __global int *d_jW,
                           __global fp *d_dN,
                           __global fp *d_dS,
                           __global fp *d_dW,
                           __global fp *d_dE,
                           __global fp *d_c,
                           __global fp *d_I) {
    (void)Nr;
    (void)d_iN;
    (void)d_jW;

    long k = (long)get_global_id(0);
    if (k < Ne) {
        int i = (int)(k / (long)Nc);
        int j = (int)(k - (long)i * (long)Nc);

        fp cN = d_c[k];
        fp cS = d_c[(long)d_iS[i] * (long)Nc + (long)j];
        fp cW = d_c[k];
        fp cE = d_c[(long)i * (long)Nc + (long)d_jE[j]];

        fp D = cN * d_dN[k] + cS * d_dS[k] + cW * d_dW[k] + cE * d_dE[k];

        d_I[k] = d_I[k] + (fp)0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global fp *d_I) {
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * (fp)255.0f;
    }
}
